def characterize_attitude(review_text):
    """
    Characterizes the attitude expressed in a review text.
    Returns a string describing the overall sentiment and attitude.
    """
    # Handle edge cases for invalid input
    if review_text is None:
        return "No review provided."

    if not isinstance(review_text, str):
        return "Invalid input: review must be a string."

    cleaned = review_text.strip().lower()

    if len(cleaned) == 0:
        return "Neutral or empty review."

    # Define positive and negative sentiment keywords
    positive_words = {
        "great", "good", "excellent", "amazing", "love", "fantastic", "wonderful",
        "awesome", "perfect", "brilliant", "five stars", "5 stars", "best", "solid"
    }

    negative_words = {
        "terrible", "awful", "bad", "poor", "horrible", "worst", "hate", "disappointing",
        "disappointed", "useless", "broken", "flawed", "one star", "1 star", "mediocre"
    }

    # Count sentiment indicators
    positive_count = sum(1 for word in positive_words if word in cleaned)
    negative_count = sum(1 for word in negative_words if word in word in cleaned)

    # Check for explicit contrast patterns like "X but Y" or "X, however Y"
    contrast_markers = ["but", "however", "though", "although", "yet", "unfortunately"]
    has_contrast = any(marker in cleaned for marker in contrast_markers)

    # Determine attitude characterization
    if positive_count > 0 and negative_count > 0:
        if has_contrast:
            return "Mixed but conflicted: the reviewer sees genuine merit but is ultimately disappointed by significant shortcomings."
        else:
            return "Mixed sentiment: both praise and criticism are present."
    elif positive_count > 0 and negative_count == 0:
        return "Positive and appreciative."
    elif negative_count > 0 and positive_count == 0:
        return "Negative and critical."
    else:
        return "Neutral or unclear attitude."


