import re

def parse_log_line(line):
    # Return None for None or empty input
    if not line:
        return None

    # Strict regex for 'YYYY-MM-DD HH:MM:SS [LEVEL] message'
    pattern = r'^(\d{4}-\d{2}-\d{2}) (\d{2}:\d{2}:\d{2}) \[([A-Z]+)\] (.+)$'
    match = re.match(pattern, line)

    if not match:
        return None

    return {
        'date': match.group(1),
        'time': match.group(2),
        'level': match.group(3),
        'message': match.group(4)
    }

